class RingBuffer:
    """In-memory ring buffer of activation frames."""
    def __init__(self, max_frames: int = 512):
        if max_frames <= 0:
            raise ValueError("max_frames must be > 0")
        self.max_frames = int(max_frames)
        self._frames: List[BufferFrame] = []
        self._cursor = 0

    def __len__(self) -> int:
        return len(self._frames)

    def add(self, frame: BufferFrame) -> None:
        if len(self._frames) < self.max_frames:
            self._frames.append(frame)
        else:
            self._frames[self._cursor] = frame
            self._cursor = (self._cursor + 1) % self.max_frames

    def snapshot(self) -> List[BufferFrame]:
        if len(self._frames) < self.max_frames or self._cursor == 0:
            return list(self._frames)
        return self._frames[self._cursor:] + self._frames[:self._cursor]

    def latest(self, k: int = 1) -> List[BufferFrame]:
        s = self.snapshot()
        return s[-k:] if k > 0 else []

def to_numpy(t: Any) -> np.ndarray:
    if isinstance(t, np.ndarray):
        return t
    if hasattr(t, "detach") and hasattr(t, "cpu") and hasattr(t, "numpy"):
        return t.detach().cpu().numpy()
    if hasattr(t, "__array__"):
        return np.asarray(t)
    raise TypeError(f"Unsupported tensor type: {type(t)}")

